CHECK_INTERVAL_SEC = 5.0


class ConformanceMonitor(Node):
    """Monitors the running ROS2 graph against the architecture model."""

    def __init__(self):
        super().__init__(node_name='conformance_monitor')
        self.diag_pub = self.create_publisher(
            DiagnosticArray, '/conformance_report', 10)
        self.timer = self.create_timer(CHECK_INTERVAL_SEC, self._check_conformance)
        self.get_logger().info(
            f'Conformance monitor started '
            f'(expecting {len(EXPECTED_NODES)} nodes, '
            f'{len(EXPECTED_TOPICS)} topics, '
            f'{len(EXPECTED_CONNECTIONS)} connections)')

    def _check_conformance(self):
        """Run all conformance checks and publish results."""
        diag_array = DiagnosticArray()
        diag_array.header.stamp = self.get_clock().now().to_msg()

        # ── Node presence check ──
        discovered = set(self.get_node_names_and_namespaces())
        node_status = DiagnosticStatus()
        node_status.name = 'node_presence'

        missing = EXPECTED_NODES - discovered
        unexpected = discovered - EXPECTED_NODES - {
            ('conformance_monitor', '/'),
        }

        if not missing:
            node_status.level = DiagnosticStatus.OK
            node_status.message = f'All {len(EXPECTED_NODES)} expected nodes present'
        else:
            node_status.level = DiagnosticStatus.ERROR
            node_status.message = f'{len(missing)} nodes missing'
            for name, ns in sorted(missing):
                node_status.values.append(
                    KeyValue(key='missing', value=f'{ns}/{name}'))

        diag_array.status.append(node_status)

        # ── Topic existence + type check ──
        discovered_topics = dict(self.get_topic_names_and_types())
        topic_status = DiagnosticStatus()
        topic_status.name = 'topic_types'

        topic_ok = 0
        topic_missing = 0
        topic_mismatch = 0

        for topic_name, expected_type in EXPECTED_TOPICS.items():
            if topic_name not in discovered_topics:
                topic_missing += 1
                topic_status.values.append(
                    KeyValue(key='missing', value=topic_name))
            else:
                actual_types = discovered_topics[topic_name]
                # ROS2 returns types as list of strings like ['sensor_msgs/msg/LaserScan']
                expected_ros_type = expected_type.replace('.', '/')
                if expected_ros_type in actual_types:
                    topic_ok += 1
                else:
                    topic_mismatch += 1
                    topic_status.values.append(
                        KeyValue(key='type_mismatch',
                                 value=f'{topic_name}: expected {expected_type}, got {actual_types}'))

        if topic_missing == 0 and topic_mismatch == 0:
            topic_status.level = DiagnosticStatus.OK
            topic_status.message = f'All {len(EXPECTED_TOPICS)} topics OK'
        elif topic_mismatch > 0:
            topic_status.level = DiagnosticStatus.ERROR
            topic_status.message = f'{topic_mismatch} type mismatches, {topic_missing} missing'
        else:
            topic_status.level = DiagnosticStatus.WARN
            topic_status.message = f'{topic_missing} topics not yet discovered'

        diag_array.status.append(topic_status)

        # ── Connection verification ──
        conn_status = DiagnosticStatus()
        conn_status.name = 'connections'
        conn_ok = 0
        conn_fail = 0

        for conn in EXPECTED_CONNECTIONS:
            # Extract topic name from source port's topic
            # (simplified: check that both source and target nodes exist)
            conn_ok += 1  # TODO: deeper endpoint verification

        conn_status.level = DiagnosticStatus.OK
        conn_status.message = f'{conn_ok} connections declared'
        diag_array.status.append(conn_status)

        # ── Publish and log ──
        self.diag_pub.publish(diag_array)

        levels = {s.level for s in diag_array.status}
        if DiagnosticStatus.ERROR in levels:
            summary = 'FAIL'
        elif DiagnosticStatus.WARN in levels:
            summary = 'WARN'
        else:
            summary = 'OK'

        self.get_logger().info(
            f'[Conformance {summary}] '
            f'Nodes: {len(EXPECTED_NODES) - len(missing)}/{len(EXPECTED_NODES)} | '
            f'Topics: {topic_ok}/{len(EXPECTED_TOPICS)} | '
            f'Connections: {conn_ok}/{len(EXPECTED_CONNECTIONS)}')


def main(args=None):
    rclpy.init(args=args)
    node = ConformanceMonitor()
    rclpy.spin(node)
    node.destroy_node()
    rclpy.shutdown()


if __name__ == '__main__':
    main()
